mapper.select:
select id, parentId, type, name, headImgUrl, 
phone, password, wallet, status, role, 
deleteStatus, city, openId, commissionType, 
commissionValue, createTime,

(select count(1) from store where find_in_set(id, agent5Ids)) as storeNum,
(select sum(if(DATE_FORMAT(finishTime, '%Y%m') = DATE_FORMAT(CURDATE(), '%Y%m'), realPayment, 0)) from card_order where status=4 and find_in_set(id, agent5Ids)) as storeMonthMoney 


(select count(1) from store where find_in_set(id, agent6Ids)) as storeNum,
(select sum(if(DATE_FORMAT(finishTime, '%Y%m') = DATE_FORMAT(CURDATE(), '%Y%m'), realPayment, 0)) from card_order where status=4 and find_in_set(id, agent6Ids)) as storeMonthMoney  

from agent
  
     and parentId = #{parentId}
     and type = #{type}
     and name like concat('%', #{name}, '%')
     and headImgUrl = #{headImgUrl}
     and phone like concat('%', #{phone}, '%')
     and password = #{password}
     and wallet = #{wallet}
     and status = #{status}
     and role = #{role}
     and deleteStatus = #{deleteStatus}
     and city = #{city}
     and openId = #{openId}
     and commissionType = #{commissionType}
     and commissionValue = #{commissionValue}
     and createTime = #{createTime}
     and id in (${ids})
    
        AND createTime between #{startTime} and #{endTime}
    

ORDER BY id DESC

    limit #{offset}, #{limit}

select count(*) from agent
  
     and parentId = #{parentId}
